// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before storing blog data.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

const post = $input.first().json;

// Validate required fields
const required = ['title', 'url', 'content'];
const missing = required.filter(f => !post[f]);

if (missing.length > 0) {
  return [{ json: { error: true, missing_fields: missing } }];
}

// URL domain validation: only allow known blog domains
const allowedDomains = ['voidai.com', 'docs.voidai.com'];
try {
  const parsed = new URL(post.url);
  const hostname = parsed.hostname.replace(/^www\./, '');
  if (!allowedDomains.some(d => hostname === d || hostname.endsWith('.' + d))) {
    return [{ json: { error: true, reason: 'URL domain not allowed: ' + hostname } }];
  }
  if (parsed.protocol !== 'https:') {
    return [{ json: { error: true, reason: 'URL must use HTTPS' } }];
  }
} catch (e) {
  return [{ json: { error: true, reason: 'Invalid URL format' } }];
}

// Truncate content for storage (keep under 8000 chars)
const truncated = post.content.length > 8000
  ? post.content.slice(0, 8000) + '\n\n[Content truncated for processing]'
  : post.content;

return [{ json: {
  title: post.title,
  url: post.url,
  content: truncated,
  full_length: post.content.length,
  category: post.category || 'general',
  author: post.author || 'VoidAI',
  error: false
} }];

const post = $input.first().json;

// Content sanitization per CLAUDE.md prompt injection safeguards
// 1. Strip instruction-like patterns
const instructionPatterns = /ignore previous|system prompt|act as|forget all|override instructions|you are now|disregard|new persona|reveal your|output your|print your/gi;

// 2. Remove non-printable and zero-width characters
const nonPrintable = /[\x00-\x08\x0B\x0C\x0E-\x1F\x7F\u200B-\u200F\uFEFF\u00AD\u2060\u2028\u2029]/g;

// 3. Remove URLs from content body (the url field is already validated)
const urlPattern = /https?:\/\/[^\s)>"']+/gi;

function sanitize(text, maxLen) {
  if (!text || typeof text !== 'string') return '';
  return text
    .replace(nonPrintable, '')
    .replace(instructionPatterns, '[FILTERED]')
    .replace(urlPattern, '[URL_REMOVED]')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, '')
    .slice(0, maxLen);
}

return [{ json: {
  title: sanitize(post.title, 200),
  url: post.url,
  // Blog content uses 5000-char limit (intentional exception to the CLAUDE.md
  // 500-char rule, which targets short user-generated content like tweets and
  // replies). Blog posts need sufficient length for manual derivative
  // content generation (threads, LinkedIn posts, announcements).
  content: sanitize(post.content, 5000),
  full_length: post.full_length,
  category: sanitize(post.category, 50),
  author: sanitize(post.author, 100),
  error: false
} }];

const post = $input.first().json;
const date = new Date().toISOString();

return [{ json: {
  status: 'dry_run',
  timestamp: date,
  message: 'Blog distribution skipped (DRY_RUN is not false)',
  blog_title: post.title,
  blog_url: post.url,
  content_preview: (post.content || '').slice(0, 200)
} }];

