parameters.jsCode:
const staticData = $getWorkflowStaticData('global');
if (!staticData.blogs) staticData.blogs = {};

const post = $('Sanitize Content').first().json;
const slug = post.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 40);
const date = new Date().toISOString().split('T')[0];
const key = `${date}-${slug}`;

const blogEntry = {
  type: 'blog-distribution',
  status: 'pending_content_generation',
  received_at: new Date().toISOString(),
  blog: {
    title: post.title,
    url: post.url,
    content: post.content.slice(0, 5000),
    category: post.category,
    author: post.author
  },
  derivatives_needed: ['x-thread', 'linkedin-post', 'discord-announcement'],
  content_brief: 'Generate derivatives using /generate-thread (for X), /generate-tweet (for LinkedIn), and manual Discord announcement'
};

staticData.blogs[key] = blogEntry;

// Cleanup: keep only last 20 entries
const blogKeys = Object.keys(staticData.blogs).sort();
if (blogKeys.length > 20) {
  blogKeys.slice(0, blogKeys.length - 20).forEach(k => delete staticData.blogs[k]);
}

return [{ json: {
  blog_title: post.title,
  blog_url: post.url,
  storage_key: key,
  status: 'pending_content_generation'
} }];

